{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "support.schema.json",
  "title": "BC FLA Separation Agreement — Child Support and Spousal Support Sub-Schema",
  "type": "object",
  "definitions": {
    "IncomeSource": {
      "type": "object",
      "properties": {
        "source_name": {
          "type": "string",
          "description": "Name or category of income source (e.g., employment, self-employment, investment, pension, disability benefits)."
        },
        "annual_amount": {
          "type": "number",
          "description": "Gross annual amount from this source in CAD."
        },
        "taxable": {
          "type": "boolean",
          "description": "Whether this income source is taxable under the Income Tax Act, R.S.C. 1985, c. 1 (5th Supp.)."
        },
        "grossed_up_amount": {
          "type": ["number", "null"],
          "description": "If non-taxable, the grossed-up equivalent for guideline income purposes per Federal Child Support Guidelines s. 19(1)(h)."
        },
        "documentation": {
          "type": "string",
          "description": "Document substantiating this source (e.g., T4, T4A, T5, financial statement)."
        }
      },
      "required": ["source_name", "annual_amount", "taxable"]
    },
    "SupportPayment": {
      "type": "object",
      "properties": {
        "amount": {
          "type": "number",
          "description": "Payment amount per period in CAD."
        },
        "frequency": {
          "type": "string",
          "enum": ["monthly", "biweekly", "semimonthly"],
          "description": "How often the payment is made."
        },
        "payment_due_date": {
          "type": "string",
          "description": "Day or date within each period payment is due (e.g., '1st of each month')."
        },
        "payment_method": {
          "type": "string",
          "enum": ["direct_deposit", "e_transfer", "cheque", "FMEP"],
          "description": "Method of payment. FMEP refers to BC Family Maintenance Enforcement Program enrollment."
        },
        "start_date": {
          "type": "string",
