          "type": "string",
          "description": "Event that triggers a support review (e.g., child completes secondary school, payor reaches age 65, recipient achieves self-sufficiency)."
        },
        "trigger_type": {
          "type": "string",
          "enum": ["scheduled_date", "milestone_event", "material_change"],
          "description": "Classification of the trigger."
        },
        "anticipated_date": {
          "type": ["string", "null"],
          "format": "date",
