        },
        "review_process": {
          "type": "string",
          "enum": ["negotiation", "mediation", "med_arb", "arbitration", "court"],
          "description": "Dispute resolution process to be followed upon trigger."
        }
      },
      "required": ["trigger_event", "trigger_type", "review_process"]
    },
    "S7Expense": {
      "type": "object",
      "properties": {
        "category": {
