            "medical_dental_premiums",
            "healthcare_uninsured",
            "primary_secondary_extracurricular",
            "post_secondary",
            "extraordinary_extracurricular"
          ],
          "description": "Category of special or extraordinary expense under Federal Child Support Guidelines s. 7. [VERIFY: s. 7 categories]"
        },
        "description": {
          "type": "string",
          "description": "Specific description of the expense."
        },
        "annual_amount_estimated": {
          "type": "number",
          "description": "Estimated gross annual cost in CAD."
        },
        "tax_deduction_credit": {
          "type": "number",
          "description": "Value of any tax deduction or credit attributable to this expense in CAD."
        },
        "net_after_tax": {
          "type": "number",
          "description": "Net annual cost after applying tax deductions or credits."
        },
        "proportional_share_payor": {
