          "minimum": 0,
          "maximum": 1,
          "description": "Payor's proportional share of net expense, based on ratio of respective guideline incomes."
        },
        "proportional_share_recipient": {
          "type": "number",
          "minimum": 0,
          "maximum": 1,
          "description": "Recipient's proportional share of net expense."
        },
        "documentation_required": {
          "type": "string",
          "description": "Documents required to substantiate expense (e.g., receipts, invoices, enrollment confirmation)."
        }
      },
      "required": [
        "category",
        "description",
        "annual_amount_estimated",
        "net_after_tax",
        "proportional_share_payor",
        "proportional_share_recipient"
      ]
    }
  },
  "properties": {
    "income_determination": {
      "type": "object",
      "description": "Income determination for each spouse for guideline support purposes.",
      "properties": {
        "spouse_1": { "$ref": "#/properties/income_determination/$defs/SpouseIncome" },
        "spouse_2": { "$ref": "#/properties/income_determination/$defs/SpouseIncome" }
      },
      "$defs": {
        "SpouseIncome": {
          "type": "object",
          "properties": {
            "line_15000_income_prior_year": {
              "type": "number",
              "description": "Total income per CRA T1 General, line 15000, for the most recent completed tax year."
