              "type": ["number", "null"],
              "description": "Estimated current-year total income per line 15000 if materially different from prior year."
            },
            "imputed_income": {
              "type": ["object", "null"],
              "description": "Income imputed under Federal Child Support Guidelines s. 19, if applicable.",
              "properties": {
                "imputed_amount": {
                  "type": "number",
                  "description": "Amount of income imputed in CAD."
                },
                "basis": {
                  "type": "string",
                  "description": "Statutory basis for imputation (e.g., s. 19(1)(a) intentionally under-employed, s. 19(1)(f) exempt from tax). [VERIFY: s. 19 subsections]"
