                "gross_self_employment_income": { "type": "number" },
                "disallowed_deductions": {
                  "type": "array",
                  "items": {
                    "type": "object",
                    "properties": {
                      "deduction_type": { "type": "string" },
                      "amount_added_back": { "type": "number" }
                    }
                  },
                  "description": "Deductions added back to income (e.g., CCA, personal vehicle, home office)."
                },
                "adjusted_self_employment_income": { "type": "number" }
              }
            },
            "non_taxable_income": {
              "type": ["object", "null"],
              "description": "Non-taxable income (e.g., disability benefits, workers' compensation) and grossed-up equivalent.",
              "properties": {
                "source": { "type": "string" },
                "annual_amount": { "type": "number" },
                "marginal_tax_rate_assumed": { "type": "number", "description": "Assumed marginal rate for gross-up." },
                "grossed_up_amount": { "type": "number" }
              }
            },
            "total_guideline_income": {
              "type": "number",
              "description": "Final guideline income for support calculation purposes."
            },
            "income_sources": {
              "type": "array",
              "items": { "$ref": "#/definitions/IncomeSource" },
              "description": "Itemized income sources."
            },
            "prescribed_income_documentation": {
              "type": "array",
              "items": { "type": "string" },
              "description": "Documents exchanged or to be exchanged per Federal Child Support Guidelines s. 21 (e.g., T1 General, T4, Notice of Assessment, corporate financial statements). [VERIFY: s. 21 prescribed documents]"
            },
            "annual_disclosure_obligation": {
              "type": "object",
              "properties": {
                "required": { "type": "boolean", "description": "Whether ongoing annual disclosure is required." },
                "due_date": { "type": "string", "description": "Annual deadline (e.g., 'June 30 of each year')." },
                "form_of_disclosure": {
                  "type": "string",
                  "description": "What must be provided (e.g., 'complete copy of T1 General, all T4/T4A/T5 slips, Notice of Assessment, and current financial statement if self-employed')."
                }
              },
              "required": ["required"]
            }
          },
          "required": ["line_15000_income_prior_year", "total_guideline_income", "prescribed_income_documentation", "annual_disclosure_obligation"]
        }
      },
      "required": ["spouse_1", "spouse_2"]
    },
    "child_support": {
      "type": "object",
      "description": "Child support terms under the Federal Child Support Guidelines, SOR/97-175, and BC Family Law Act, S.B.C. 2011, c. 25, Part 7.",
      "properties": {
        "payor": {
          "type": "string",
          "enum": ["spouse_1", "spouse_2"],
          "description": "The spouse obligated to pay child support."
        },
        "applicable_guideline": {
          "type": "string",
          "const": "Federal Child Support Guidelines, SOR/97-175",
          "description": "Applicable guideline instrument."
        },
        "payor_guideline_income": {
          "type": "number",
          "description": "Payor's guideline income for table amount lookup."
        },
        "recipient_guideline_income": {
          "type": ["number", "null"],
          "description": "Recipient's guideline income, required for shared or split parenting arrangements under s. 8 or s. 9."
        },
        "children": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "name": { "type": "string" },
              "date_of_birth": { "type": "string", "format": "date" },
              "child_of_marriage": {
                "type": "boolean",
                "description": "Whether child qualifies as child of the marriage per Divorce Act, R.S.C. 1985, c. 3 (2nd Supp.), s. 2(1), or child under FLA s. 146. [VERIFY: FLA s. 146 definition of child for support]"
              }
            }
          },
          "description": "Children for whom support is payable."
        },
        "parenting_arrangement_for_cs": {
          "type": "string",
