          "type": ["object", "null"],
          "description": "Set-off calculation for shared or split parenting under s. 8 or s. 9.",
          "properties": {
            "spouse_1_table_amount": { "type": "number" },
            "spouse_2_table_amount": { "type": "number" },
            "set_off_amount": { "type": "number", "description": "Difference between the two table amounts." },
            "higher_income_parent": { "type": "string", "enum": ["spouse_1", "spouse_2"] },
