        "end_event": {
          "type": "string",
          "description": "Event upon which child support terminates (e.g., 'child ceases to be a child of the marriage per Divorce Act s. 2(1) or is no longer a child under FLA s. 146'). [VERIFY: FLA s. 146 and s. 147 re child support obligation end]"
        },
        "section_7_expenses": {
          "type": "object",
          "description": "Special or extraordinary expenses under Federal Child Support Guidelines s. 7.",
          "properties": {
            "expenses": {
              "type": "array",
              "items": { "$ref": "#/definitions/S7Expense" }
            },
            "reconciliation_cadence": {
              "type": "string",
              "description": "How often s. 7 expenses are reconciled (e.g., 'quarterly with receipts within 30 days of quarter end')."
            },
            "pre_approval_required": {
              "type": "boolean",
              "description": "Whether both spouses must consent before incurring a new s. 7 expense."
            }
          },
          "required": ["expenses", "reconciliation_cadence"]
