      },
      "required": ["payor", "applicable_guideline", "payor_guideline_income", "parenting_arrangement_for_cs", "table_amount", "payment", "end_event"]
    },
    "retroactive_child_support": {
      "type": ["object", "null"],
      "description": "Retroactive child support claim, resolved per DBS v. SRG, 2006 SCC 37, and Michel v. Graydon, 2020 SCC 24. [VERIFY: Michel v. Graydon citation 2020 SCC 24]",
      "properties": {
        "claimed": {
          "type": "boolean",
          "description": "Whether a retroactive claim was made."
        },
        "resolved": {
          "type": "boolean",
          "description": "Whether the retroactive claim is fully resolved in this agreement."
        },
        "period_covered": {
          "type": "object",
          "properties": {
            "from": { "type": "string", "format": "date" },
            "to": { "type": "string", "format": "date" }
