        },
        "amount_agreed": {
          "type": "number",
          "description": "Total retroactive amount agreed in CAD."
        },
        "payment_plan": {
          "type": "string",
          "description": "Terms for paying the retroactive amount (e.g., lump sum by date, instalments)."
        }
      },
      "required": ["claimed", "resolved"]
