              "type": ["string", "null"],
              "format": "date",
              "description": "Fixed end date if applicable."
            },
            "review_event": {
              "type": ["string", "null"],
              "description": "Event triggering end or review if type is to_review_event."
            }
          },
          "required": ["type"]
        },
        "indexation": {
          "type": "object",
          "description": "Annual cost-of-living adjustment.",
          "properties": {
            "indexed": { "type": "boolean" },
            "index_reference": {
              "type": ["string", "null"],
              "description": "Index used (e.g., 'Statistics Canada CPI All-Items, Vancouver, B.C.')."
