            "adjustment_cadence": {
              "type": ["string", "null"],
              "description": "When adjustment takes effect (e.g., 'January 1 of each year')."
            }
          },
          "required": ["indexed"]
        },
        "lump_sum_option": {
          "type": ["object", "null"],
          "description": "Lump sum spousal support in lieu of or in addition to periodic payments.",
