            },
            "acknowledgment_change_of_conditions": {
              "type": "string",
              "description": "Acknowledgment that conditions may change but the waiver is intended to be final and binding."
            },
            "acknowledgment_ila_on_waiver": {
              "type": "boolean",
              "description": "Confirmation that the waiving spouse received independent legal advice specifically on the spousal support waiver."
            },
            "reasons_for_waiver": {
              "type": "string",
              "description": "Reasons supporting the waiver (e.g., both spouses self-sufficient, short marriage, equalized by property division)."
            }
          },
          "required": ["spousal_support_waived", "acknowledgment_compensatory_entitlement_waived", "acknowledgment_change_of_conditions", "acknowledgment_ila_on_waiver"]
        }
      },
      "required": ["entitlement_basis", "applicable_guideline", "ssag_calculation", "duration"]
    },
    "support_security": {
      "type": "object",
      "description": "Security for support obligations.",
      "properties": {
        "life_insurance": {
          "type": ["object", "null"],
          "description": "Life insurance policy maintained to secure support obligations.",
          "properties": {
            "insurer": { "type": "string" },
            "policy_number": { "type": "string" },
            "face_amount": { "type": "number", "description": "Minimum face amount in CAD." },
            "beneficiary_designation": { "type": "string", "description": "Irrevocable beneficiary designation (e.g., recipient spouse in trust for children)." },
