          "properties": {
            "property_description": { "type": "string" },
            "pid": { "type": "string", "description": "BC Land Title PID." },
            "amount_secured": { "type": "number" },
            "discharge_conditions": { "type": "string" }
          }
        },
        "fmep_assignment": {
          "type": "boolean",
          "description": "Whether the agreement is assigned to the BC Family Maintenance Enforcement Program for enforcement."
        }
      }
    },
    "support_review_and_variation": {
      "type": "object",
      "description": "Review and variation provisions for child and spousal support.",
      "properties": {
        "scheduled_review_dates": {
          "type": "array",
          "items": { "type": "string", "format": "date" },
          "description": "Specific future dates on which support will be reviewed."
