        },
        "dispute_resolution_process": {
          "type": "array",
          "items": {
            "type": "string",
            "enum": ["negotiation", "mediation", "med_arb", "arbitration", "court"]
          },
          "description": "Ordered sequence of dispute resolution steps before court application. FLA s. 4 encourages out-of-court resolution."
        }
      },
      "required": ["automatic_review_triggers", "material_change_threshold", "dispute_resolution_process"]
    },
    "tax_treatment": {
      "type": "object",
      "description": "Income tax treatment of support payments under the Income Tax Act, R.S.C. 1985, c. 1 (5th Supp.).",
      "properties": {
        "child_support_tax_treatment": {
          "type": "string",
          "const": "not_deductible_not_includable",
          "description": "Post-May 1997 child support: not deductible by payor, not includable by recipient, per ITA s. 56.1(4) and s. 60.1(4)."
        },
        "spousal_support_periodic_tax_treatment": {
          "type": "object",
          "description": "Periodic spousal support: deductible by payor under ITA s. 60(b), includable by recipient under ITA s. 56(1)(b). [VERIFY: s. 60(b) and s. 56(1)(b) current references]",
          "properties": {
            "deductible_to_payor": { "type": "boolean", "const": true },
            "includable_to_recipient": { "type": "boolean", "const": true }
          }
        },
        "lump_sum_spousal_support_tax_treatment": {
          "type": "object",
          "description": "Lump sum spousal support: generally not deductible to payor and not includable to recipient.",
          "properties": {
            "deductible_to_payor": { "type": "boolean", "const": false },
            "includable_to_recipient": { "type": "boolean", "const": false }
          }
        },
        "retroactive_support_tax_treatment": {
          "type": "string",
          "description": "Retroactive periodic spousal support may be deductible/includable in the years to which it relates; recipient may request CRA reassessment for prior years per ITA s. 60.1(3). Retroactive child support is not deductible/includable. [VERIFY: s. 60.1(3) applicability]"
        }
      },
      "required": ["child_support_tax_treatment", "spousal_support_periodic_tax_treatment", "lump_sum_spousal_support_tax_treatment", "retroactive_support_tax_treatment"]
    }
  },
  "required": [
    "income_determination",
    "child_support",
    "spousal_support",
    "support_security",
    "support_review_and_variation",
    "tax_treatment"
  ]
}
